ee:variables.ee:set-variable:
%dw 2.0
output application/json
import toBase64 from dw::core::Binaries
---
{
	"method": Mule::p('b2b-p21-sys-api.view.method'),
//	"host": Mule::p('b2b-p21-sys-api.host'),
//	"port": Mule::p('b2b-p21-sys-api.port'),
	"host":"localhost",
	"port": "8092",
	"basePath": Mule::p('b2b-p21-sys-api.basePath'),
	"path": Mule::p('b2b-p21-sys-api.view.path'),
	"headers": {
		"x-correlation-id": vars.integration.correlationId
	},
	"queryParams": {
		"transactionType": Mule::p('b2b-p21-sys-api.transactionType.salesOrder'),
		"purpose": Mule::p('b2b-p21-sys-api.purpose.validation'),
		"validationMode" : "xref",
		"companyId": "TPA",
		"ediRefId" : (payload[0].b2bMessage.header.partyInformation
    filter ($.qualifier == "BY"))[0].identificationCode default ""
	},
	"uriParams": {
	},
	"body": {
	},
	"untilsuccessful": {
		"maxRetries": Mule::p('b2b-p21-sys-api.view.untilsuccessful.maxRetries'),
		"interval": Mule::p('b2b-p21-sys-api.view.untilsuccessful.interval')
	}
}

%dw 2.0
output application/json

var response = vars.xref
var hasInvalidEdiXref = isEmpty(response)

---
{
    isValid: !hasInvalidEdiXref,
    validationErrors:
        if (hasInvalidEdiXref)
            {
                ediXrefId: [
                    "The EDI X Reference ID is not valid for Company ID TPA."
                ]
            }
        else
            {}
}

%dw 2.0
output application/json
import toBase64 from dw::core::Binaries
---
{
	"method": Mule::p('b2b-p21-sys-api.view.method'),
//	"host": Mule::p('b2b-p21-sys-api.host'),
//	"port": Mule::p('b2b-p21-sys-api.port'),
	"host": "localhost",
	"port": "8092",
	"basePath": Mule::p('b2b-p21-sys-api.basePath'),
	"path": Mule::p('b2b-p21-sys-api.view.path'),
	"headers": {
		"x-correlation-id": vars.integration.correlationId
	},
	"queryParams": {
		"transactionType": Mule::p('b2b-p21-sys-api.transactionType.salesOrder'),
		"purpose": Mule::p('b2b-p21-sys-api.purpose.validation'),
		"validationMode": "customerPart",
		"customerId": vars.xref.customer_id[0],
		"businesskey":(vars.initialPayload flatMap ((x) -> x.b2bMessage.detail.itemDetails))
    map ((item) -> item.buyersPartNumber)
    joinBy ",",
	},
	"uriParams": {
	},
	"body": {
	},
	"untilsuccessful": {
		"maxRetries": Mule::p('b2b-p21-sys-api.view.untilsuccessful.maxRetries'),
		"interval": Mule::p('b2b-p21-sys-api.view.untilsuccessful.interval')
	}
}
